
import {
  defineComponent,
  onDeactivated,
  provide,
  reactive,
  ref,
  toRefs,
  watch,
} from "vue";
import AmultitaskingSearch from "../../../components/Amultitasking/AmultitaskingSearch.vue";
import AmultitaskingTable from "../../../components/Amultitasking/AmultitaskingTable.vue";
import { getTaskInfo } from "@/server/http/api/Amultitasking";
import { useRouter } from "vue-router";
export default defineComponent({
  name: "Starttest",
  components: { AmultitaskingSearch, AmultitaskingTable },

  setup() {
    // ===
    const dataList = ref([]);
    const total = ref(0);
    let options = reactive({
      pageNum: 1,
      pageSize: 10,
    });
    const formState: any = {};
    function init() {
      getTaskInfo(formState).then((res: any) => {
        //console.log(res.data.data);
        if (res.data.code === 200) {
          dataList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }
    function filterStarttest(form: any) {
      Object.assign(formState, form);
      Object.assign(formState, options);
      init();
    }
    watch(options, () => {
      Object.assign(formState, options);
      init();
    });

    // ===
    const router = useRouter();
    function checkClick(rowData: any) {
      console.info(rowData);
      router.push({ name: "StarttestMenm", params: { id: rowData.taskId } });
    }

    return {
      dataList,
      checkClick,
      filterStarttest,
      total,
      ...toRefs(options),
    };
  },
});
